import { db } from "./firebase";
import { ref, push, set, get, child, update } from "firebase/database";
import { PurchaseOrder, Requisition, POStatus } from "@/types";
import { getVendor } from "./vendors";

const COLLECTION_NAME = "purchase_orders";

const generatePONumber = async (): Promise<string> => {
    // Simple autoincrement logic or timestamp based
    // Ideally use a transaction counter in DB
    const timestamp = Date.now().toString().slice(-6);
    return `PO-2026-${timestamp}`;
};

export const createPOFromRequisition = async (requisition: Requisition, userId: string) => {
    try {
        const poNumber = await generatePONumber();
        const vendor = await getVendor(requisition.vendorId!);

        const poRef = ref(db, COLLECTION_NAME);
        const newPORef = push(poRef);

        const newPO: Omit<PurchaseOrder, 'id'> = {
            poNumber,
            requisitionId: requisition.id!,
            vendorId: requisition.vendorId!,
            vendorName: requisition.vendorName!,
            vendorEmail: vendor?.email,
            items: requisition.items,
            totalAmount: requisition.totalAmount,
            currency: requisition.currency,
            status: 'ISSUED',
            issuedAt: new Date().toISOString() as any, // RTDB stores string
            issuedBy: userId
        };

        await set(newPORef, newPO);

        // Update Requisition status
        const reqRef = ref(db, `requisitions/${requisition.id}`);
        await update(reqRef, { status: 'ORDERED' });

        return newPORef.key;
    } catch (error) {
        console.error("Error creating PO:", error);
        throw error;
    }
};

export const getPurchaseOrders = async (): Promise<PurchaseOrder[]> => {
    try {
        const dbRef = ref(db);
        const snapshot = await get(child(dbRef, COLLECTION_NAME));

        if (snapshot.exists()) {
            const data = snapshot.val();
            return Object.entries(data).map(([key, v]: [string, any]) => ({
                id: key,
                ...v,
                issuedAt: new Date(v.issuedAt),
            })) as PurchaseOrder[];
        }
        return [];
    } catch (error) {
        console.error("Error fetching POs", error);
        return [];
    }
};

export const updatePOStatus = async (poId: string, status: POStatus) => {
    const poRef = ref(db, `${COLLECTION_NAME}/${poId}`);
    const updates: any = { status };
    if (status === 'RECEIVED') {
        updates.receivedAt = new Date().toISOString();
    }
    await update(poRef, updates);
};

export const logDeliveryEvent = async (poId: string, action: 'SENT' | 'OPENED' | 'ACKNOWLEDGED', performer: string) => {
    try {
        const poRef = ref(db, `${COLLECTION_NAME}/${poId}`);
        const snapshot = await get(poRef);
        if (!snapshot.exists()) return;

        const currentData = snapshot.val();
        const history = currentData.deliveryHistory || [];

        const newEvent = {
            timestamp: new Date().toISOString(),
            action,
            performedBy: performer
        };

        const updates: any = {
            deliveryHistory: [...history, newEvent]
        };

        // Update top-level status based on tracking
        if (action === 'SENT') updates.status = 'SENT';
        if (action === 'OPENED' && currentData.status !== 'ACKNOWLEDGED') updates.status = 'OPENED';
        if (action === 'ACKNOWLEDGED') updates.status = 'ACKNOWLEDGED';

        if (action === 'OPENED' && !currentData.firstViewedAt) {
            updates.firstViewedAt = newEvent.timestamp;
        }
        if (action === 'OPENED') {
            updates.lastViewedAt = newEvent.timestamp;
        }

        await update(poRef, updates);
    } catch (error) {
        console.error("Error logging delivery event", error);
    }
};

export const getPurchaseOrderById = async (id: string): Promise<PurchaseOrder | null> => {
    try {
        const dbRef = ref(db);
        const snapshot = await get(child(dbRef, `${COLLECTION_NAME}/${id}`));
        if (snapshot.exists()) {
            const v = snapshot.val();
            return {
                id,
                ...v,
                issuedAt: new Date(v.issuedAt),
            } as PurchaseOrder;
        }
        return null;
    } catch (error) {
        console.error("Error fetching PO by ID", error);
        return null;
    }
};
