import { getPurchaseOrders } from "./purchaseOrders";
import { getRequisitions } from "./requisitions"; // To get department info if not on PO

export interface DashboardEvent {
    id: string;
    type: 'REQUISITION' | 'ORDER' | 'INVOICE' | 'BUDGET';
    title: string;
    description: string;
    amount?: number;
    currency?: string;
    timestamp: Date;
    user: string;
    status: string;
}

export interface SpendSummary {
    totalSpend: number;
    pendingSpend: number;
    savings: number;
    avgApprovalDays: number;
    spendByDepartment: Record<string, number>;
    spendByVendor: Record<string, number>;
    recentTransactions: any[];
    activityFeed: DashboardEvent[];
}

export const getSpendAnalytics = async (): Promise<SpendSummary> => {
    const [pos, reqs] = await Promise.all([
        getPurchaseOrders(),
        getRequisitions()
    ]);

    const reqMap = new Map(reqs.map(r => [r.id!, r]));

    const summary: SpendSummary = {
        totalSpend: 0,
        pendingSpend: 0,
        savings: 0,
        avgApprovalDays: 2.4, // Simplified mock
        spendByDepartment: {},
        spendByVendor: {},
        recentTransactions: [],
        activityFeed: []
    };

    pos.forEach(po => {
        const amount = Number(po.totalAmount);
        if (po.status !== 'CLOSED') {
            summary.totalSpend += amount;
        }

        const vendor = po.vendorName || 'Unknown';
        summary.spendByVendor[vendor] = (summary.spendByVendor[vendor] || 0) + amount;

        const req = reqMap.get(po.requisitionId);
        const dept = req?.department || 'Unassigned';
        summary.spendByDepartment[dept] = (summary.spendByDepartment[dept] || 0) + amount;

        // Mock Savings: 5% of PO value for demo
        summary.savings += (amount * 0.05);

        // Add to Activity Feed (from POs)
        summary.activityFeed.push({
            id: po.id!,
            type: 'ORDER',
            title: `PO ${po.poNumber} Issued`,
            description: `Order issued to ${po.vendorName}`,
            amount: po.totalAmount,
            currency: po.currency,
            timestamp: po.issuedAt,
            user: 'System',
            status: po.status
        });

        // Add Delivery Events to Feed
        po.deliveryHistory?.forEach(log => {
            summary.activityFeed.push({
                id: `${po.id}-${log.timestamp}`,
                type: 'ORDER',
                title: log.action === 'OPENED' ? 'Vendor Opened PO' : log.action === 'ACKNOWLEDGED' ? 'Vendor Acknowledged PO' : 'Link Emailed',
                description: `${log.action === 'OPENED' ? 'PO ' + po.poNumber + ' viewed by vendor' : log.action === 'ACKNOWLEDGED' ? 'Vendor confirmed receipt of ' + po.poNumber : 'PO ' + po.poNumber + ' link sent to vendor'}`,
                amount: po.totalAmount,
                currency: po.currency,
                timestamp: new Date(log.timestamp),
                user: log.performedBy === 'VENDOR' ? po.vendorName : 'Admin',
                status: log.action
            });
        });
    });

    // Add Requisitions to Feed
    reqs.slice(0, 5).forEach(req => {
        if (req.status === 'PENDING') {
            summary.activityFeed.push({
                id: req.id!,
                type: 'REQUISITION',
                title: 'New Requisition',
                description: `${req.requesterName} requested ${req.items[0]?.description}`,
                amount: req.totalAmount,
                currency: req.currency,
                timestamp: req.createdAt,
                user: req.requesterName,
                status: req.status
            });
        }
    });

    summary.recentTransactions = pos
        .sort((a, b) => b.issuedAt.getTime() - a.issuedAt.getTime())
        .slice(0, 5);

    summary.activityFeed.sort((a, b) => b.timestamp.getTime() - a.timestamp.getTime());

    return summary;
};
